**`src/login.js` — React Login Component (Frontend)**

```jsx
import { useState, useEffect } from 'react';
import axios from 'axios';

export default function LoginPage() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState(null);

  async function handleSubmit(event) {
    event.preventDefault();
    setIsLoading(true);
    setError(null);

    try {
      const response = await axios.post('/api/auth/login', {
        email,
        password
      });

      if (response.data.token) {
        localStorage.setItem('token', response.data.token);
        window.location.href = '/dashboard';
      }
    } catch (err) {
      setError(err.response?.data?.message || 'Login failed');
    } finally {
      setIsLoading(false);
    }
  }

  return (
    <div className="login-container">
      {/* ... UI rendering code ... */}
    </div>
  );
}
```

---

**What this shows:**

This is the **frontend** login page component. It:
1. Collects email and password from the user
2. Sends a POST request to `/api/auth/login` with the credentials
3. If successful, stores the JWT token in localStorage and redirects to the dashboard
4. Shows error messages if login fails

